// Nodo Function - Test Simple
msg.headers = {
    "Content-Type": "application/json",
    "User-Agent": "Mozilla/5.0 (compatible; Node-RED-API/1.0)"
};

msg.payload = {
    "api_key": "Corona1234$",
    "test": "hello"
};

return msg;

// Extraer los datos de la estructura correcta
let datos = [];

// La estructura tiene recordsets[0] con el array de registros
if (msg.payload && 
    msg.payload.recordsets && 
    Array.isArray(msg.payload.recordsets) && 
    msg.payload.recordsets.length > 0 && 
    Array.isArray(msg.payload.recordsets[0])) {

    datos = msg.payload.recordsets[0];
    node.warn(`✅ Datos extraídos de recordsets: ${datos.length} registros`);

} else if (Array.isArray(msg.payload)) {
    // Fallback por si es array directo
    datos = msg.payload;
    node.warn(`✅ Datos en formato array: ${datos.length} registros`);
} else {
    node.warn("❌ Formato de datos no reconocido");
    node.warn("Estructura recibida: " + JSON.stringify(msg.payload).substring(0, 200));
    return null;
}

// Validar que tenemos datos
if (!datos || datos.length === 0) {
    node.warn("⚠️ No hay registros para procesar");
    return null;
}

const LOTE_TAMANO = 500; // Puedes ajustar este valor
const TOTAL_REGISTROS = datos.length;
const TOTAL_LOTES = Math.ceil(TOTAL_REGISTROS / LOTE_TAMANO);

node.warn(`📊 Total registros: ${TOTAL_REGISTROS}, Lotes: ${TOTAL_LOTES}`);

// Crear array de lotes
const lotes = [];
for (let i = 0; i < TOTAL_REGISTROS; i += LOTE_TAMANO) {
    const lote = datos.slice(i, i + LOTE_TAMANO);

    // Validar y limpiar cada registro
    const loteValidado = lote.map(item => ({
        NOMBRE: item.NOMBRE || item.nombre || '',
        CUIT: item.CUIT ? item.CUIT.toString().trim() : (item.cuit ? item.cuit.toString().trim() : ''),
        CALLE: item.CALLE || item.calle || item.domicilio || '',
        MAIL: item.MAIL || item.mail || item.email || ''
    })).filter(item => item.NOMBRE && item.CUIT); // Solo registros válidos

    if (loteValidado.length > 0) {
        lotes.push({
            payload: {
                api_key: "Corona1234$",
                batch_number: Math.floor(i / LOTE_TAMANO) + 1,
                total_batches: TOTAL_LOTES,
                data: loteValidado
            },
            headers: {
                "Content-Type": "application/json"
            },
            lote_actual: Math.floor(i / LOTE_TAMANO) + 1,
            total_lotes: TOTAL_LOTES
        });
    }
}

// Guardar los lotes pendientes en el contexto
flow.set("lotes_pendientes", lotes.slice(1));
flow.set("total_lotes", TOTAL_LOTES);

// Mostrar información del primer lote
if (lotes.length > 0) {
    const primerLote = lotes[0];
    node.warn(`📤 Enviando lote 1/${TOTAL_LOTES} con ${primerLote.payload.data.length} registros válidos`);

    // Mostrar ejemplo del primer registro para verificar
    if (primerLote.payload.data.length > 0) {
        node.warn("📝 Ejemplo: " + JSON.stringify(primerLote.payload.data[0]));
    }

    return primerLote;
} else {
    node.warn("⚠️ No se generaron lotes válidos");
    return null;
}

const respuesta = msg.payload;
const lote_actual = msg.lote_actual;
const total_lotes = msg.total_lotes;

// Mostrar la respuesta completa para debug
node.warn(`📥 Respuesta del servidor (lote ${lote_actual}):`);
node.warn(typeof respuesta === 'string' ? respuesta : JSON.stringify(respuesta));

// Si la respuesta es un string, intentar parsearla
let respuestaObj = respuesta;
if (typeof respuesta === 'string') {
    try {
        respuestaObj = JSON.parse(respuesta);
    } catch (e) {
        node.warn(`❌ Error parseando JSON: ${e.message}`);
        node.warn(`Respuesta raw: ${respuesta}`);
        return null;
    }
}

// Verificar si la respuesta fue exitosa
if (!respuestaObj || !respuestaObj.success) {
    node.warn(`❌ Error en lote ${lote_actual}: ${respuestaObj?.error || 'Error desconocido'}`);
    node.warn(`Respuesta completa: ${JSON.stringify(respuestaObj)}`);
    return null;
}

node.warn(`✅ Lote ${lote_actual}/${total_lotes} procesado: ${respuestaObj.insertados || 0} insertados, ${respuestaObj.actualizados || 0} actualizados`);

const lotes_pendientes = flow.get("lotes_pendientes") || [];

if (lotes_pendientes.length > 0) {
    const siguiente_lote = lotes_pendientes.shift();
    flow.set("lotes_pendientes", lotes_pendientes);

    node.warn(`📤 Enviando lote ${siguiente_lote.lote_actual}/${total_lotes} con ${siguiente_lote.payload.data.length} registros...`);

    return {
        payload: siguiente_lote.payload,
        headers: siguiente_lote.headers,
        lote_actual: siguiente_lote.lote_actual,
        total_lotes: siguiente_lote.total_lotes
    };

} else {
    node.warn(`🎉 ¡Sincronización completada! Total lotes: ${total_lotes}`);
    flow.set("lotes_pendientes", null);
    flow.set("total_lotes", null);
    return null;
}
